import { DndContext, type DragEndEvent, PointerSensor, useSensor, useSensors } from "@dnd-kit/core";
import { CSS } from "@dnd-kit/utilities";
import { useDraggable, useDroppable } from "@dnd-kit/core";
import clsx from "clsx";
import {
  AlertTriangle,
  Check,
  ChevronRight,
  CircleDashed,
  Code2,
  Copy,
  ExternalLink,
  FolderPlus,
  Loader2,
  Play,
  Plus,
  RefreshCw,
  Save,
  Search,
  Trash2,
  X
} from "lucide-react";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import type { ReactElement } from "react";
import type {
  BoardSnapshot,
  ClarificationQuestion,
  CodexStatus,
  GitMetadata,
  ProjectSummary,
  RelayColumn,
  RendererRunEvent,
  RunStatus,
  TicketDraftErrorPayload,
  TicketPriority,
  TicketRecord,
  TicketSummary
} from "@shared/types";
import { AgentActivityPanel, AgentLogViewer, AgentProgressSummary } from "./components/AgentActivity";
import { ClarificationPanel } from "./components/ClarificationPanel";
import { GitMetadataPill, loadingGitMetadata } from "./components/GitMetadata";
import { MarkdownBlock } from "./components/MarkdownBlock";
import { mergeRunEvents } from "./lib/agentProgress";
import {
  createTicketShortcutLabel,
  isCreateTicketShortcut,
  KeyboardShortcutProvider,
  ticketNavigationDirection,
  ticketNavigationShortcutLabel,
  useKeyboardShortcut,
  useShortcutOverlay,
  type ShortcutDirection
} from "./lib/keyboardShortcuts";
import { emptyTicketMarkdown, markdownFromDraft } from "./lib/markdown";

type Toast = { kind: "info" | "error" | "success"; message: string } | null;
type LocalAgentProgress = { status: RunStatus; startedAt: string; endedAt?: string | null };

const priorityOptions: TicketPriority[] = ["low", "medium", "high", "urgent"];

const initialCodexStatus: CodexStatus = {
  sdkAvailable: false,
  cliAvailable: false,
  cliVersion: null,
  authenticated: null,
  message: "Checking Codex..."
};

const shortPath = (projectPath: string): string => {
  const parts = projectPath.split("/");
  if (parts.length <= 4) return projectPath;
  return `.../${parts.slice(-3).join("/")}`;
};

const projectDisclosureTargetId = (project: ProjectSummary, index: number): string => {
  const stableKey = project.projectId ?? `${project.name}-${index}-${project.path}`;
  return `project-swimlanes-${stableKey.replace(/[^a-zA-Z0-9_-]/g, "-")}`;
};

const ticketCountLabel = (count: number): string => `${count} ${count === 1 ? "ticket" : "tickets"}`;

const runLabel = (status: TicketSummary["runStatus"]): string => {
  switch (status) {
    case "idle":
      return "Idle";
    case "running":
      return "Running";
    case "blocked":
      return "Blocked";
    case "failed":
      return "Failed";
    case "completed":
      return "Codex Done";
    case "cancelled":
      return "Cancelled";
    case "drafting":
      return "Drafting";
    default:
      return "Idle";
  }
};

// Markdown audit: create-ticket drafts, ticket detail bodies, clarification text,
// and generated Codex completion/final-response console events use MarkdownBlock.
// Board excerpts and command output stay plain text because they are summaries/logs.
const copyToast = (kind: "markdown" | "code"): Toast => ({
  kind: "success",
  message: kind === "code" ? "Code copied." : "Markdown source copied."
});

export function ProjectSidebar({
  projects,
  selectedPath,
  gitMetadataByPath,
  loading,
  onAdd,
  onSelect,
  onRemove,
  onReveal,
  defaultExpandedProjectPaths = []
}: {
  projects: ProjectSummary[];
  selectedPath: string | null;
  gitMetadataByPath: Record<string, GitMetadata | undefined>;
  loading: boolean;
  onAdd: () => void;
  onSelect: (projectPath: string) => void;
  onRemove: (projectPath: string) => void;
  onReveal: (projectPath: string) => void;
  defaultExpandedProjectPaths?: string[];
}): ReactElement {
  const [expandedProjectPaths, setExpandedProjectPaths] = useState<Set<string>>(() => new Set(defaultExpandedProjectPaths));

  const toggleProject = useCallback((projectPath: string): void => {
    setExpandedProjectPaths((current) => {
      const next = new Set(current);
      if (next.has(projectPath)) {
        next.delete(projectPath);
      } else {
        next.add(projectPath);
      }
      return next;
    });
  }, []);

  return (
    <aside className="sidebar" aria-label="Projects">
      <div className="brand">
        <div className="brand-mark">R</div>
        <div>
          <h1>Relay</h1>
          <p>Local Codex boards</p>
        </div>
      </div>

      <button className="primary-button full" onClick={onAdd} disabled={loading}>
        {loading ? <Loader2 className="spin" size={16} /> : <FolderPlus size={16} />}
        Add Project
      </button>

      <div className="sidebar-list" role="list">
        {projects.map((project, index) => {
          const gitMetadata = gitMetadataByPath[project.path] ?? loadingGitMetadata();
          const expanded = expandedProjectPaths.has(project.path);
          const swimlaneListId = projectDisclosureTargetId(project, index);
          return (
            <div className="project-group" key={project.path} role="listitem">
              <div className={clsx("project-row-shell", selectedPath === project.path && "selected")}>
                <button
                  type="button"
                  className="project-disclosure"
                  onClick={() => toggleProject(project.path)}
                  aria-expanded={expanded}
                  aria-controls={swimlaneListId}
                  aria-label={`${expanded ? "Collapse" : "Expand"} ${project.name} swimlanes`}
                >
                  <ChevronRight className={clsx("project-disclosure-icon", expanded && "expanded")} size={15} />
                </button>
                <button
                  type="button"
                  className={clsx("project-row", selectedPath === project.path && "selected")}
                  onClick={() => onSelect(project.path)}
                  aria-current={selectedPath === project.path ? "page" : undefined}
                >
                  <span className="project-main">
                    <span className="project-name">{project.name}</span>
                    <span className="project-path">{shortPath(project.path)}</span>
                    <GitMetadataPill metadata={gitMetadata} compact />
                  </span>
                  <span className="project-badges">
                    {project.health !== "ok" && <AlertTriangle size={13} />}
                    {project.activeRunCount > 0 && <CircleDashed size={13} />}
                  </span>
                </button>
              </div>
              {expanded && (
                <div id={swimlaneListId} className="project-swimlane-list" role="list" aria-label={`${project.name} swimlanes`}>
                  {project.swimlanes.length > 0 ? (
                    project.swimlanes.map((swimlane) => (
                      <div
                        className="project-swimlane-row"
                        key={swimlane.id}
                        role="listitem"
                        aria-label={`${swimlane.name}: ${ticketCountLabel(swimlane.ticketCount)}`}
                      >
                        <span className="project-swimlane-name">{swimlane.name}</span>
                        <span className="project-swimlane-count" aria-hidden="true">
                          {swimlane.ticketCount}
                        </span>
                      </div>
                    ))
                  ) : (
                    <div className="project-swimlane-empty" role="listitem">
                      No swimlanes
                    </div>
                  )}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {selectedPath && (
        <div className="sidebar-actions">
          <button onClick={() => onReveal(selectedPath)}>
            <ExternalLink size={15} />
            Reveal
          </button>
          <button onClick={() => onRemove(selectedPath)}>
            <X size={15} />
            Remove
          </button>
        </div>
      )}
    </aside>
  );
}

function DroppableColumn({
  column,
  tickets,
  selectedTicketId,
  onOpen,
  onTicketFocus,
  onTicketButtonRef
}: {
  column: RelayColumn;
  tickets: TicketSummary[];
  selectedTicketId: string | null;
  onOpen: (ticketId: string) => void;
  onTicketFocus: (ticketId: string) => void;
  onTicketButtonRef: (ticketId: string, node: HTMLButtonElement | null) => void;
}): ReactElement {
  const { setNodeRef, isOver } = useDroppable({ id: column.id });
  return (
    <section ref={setNodeRef} className={clsx("board-column", isOver && "over")}>
      <header className="column-header">
        <h2>{column.name}</h2>
        <span>{tickets.length}</span>

:root {
  color-scheme: dark;
  --relay-font-sans:
    Inter, "DM Sans", ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  --relay-font-mono: "SF Mono", "SFMono-Regular", Consolas, "Liberation Mono", Menlo, monospace;
  --relay-bg: #0a0a09;
  --relay-chrome: #0d0d0c;
  --relay-sidebar: #11110f;
  --relay-surface: #151512;
  --relay-surface-2: #191916;
  --relay-surface-3: #20201c;
  --relay-surface-hover: #23231f;
  --relay-surface-active: #2a2925;
  --relay-popover: #181815;
  --relay-input: #121210;
  --relay-text: #f0eee7;
  --relay-text-muted: #aaa49a;
  --relay-text-subtle: #7f786e;
  --relay-text-inverse: #ffffff;
  --relay-border-soft: rgb(255 255 255 / 5%);
  --relay-border: rgb(255 255 255 / 8%);
  --relay-border-strong: rgb(255 255 255 / 14%);
  --relay-primary: #9F1D1B;
  --relay-primary-hover: #B32623;
  --relay-primary-active: #841715;
  --relay-primary-muted: rgb(159 29 27 / 14%);
  --relay-primary-text: #D96760;
  --relay-ring: #B83A34;
  --relay-info: #8fb8ff;
  --relay-info-muted: rgb(143 184 255 / 14%);
  --relay-success: #87d38b;
  --relay-success-muted: rgb(135 211 139 / 13%);
  --relay-warning: #e7c36a;
  --relay-warning-muted: rgb(231 195 106 / 14%);
  --relay-danger: #ff8f80;
  --relay-danger-muted: rgb(255 143 128 / 14%);
  --relay-info-text: #b5ccff;
  --relay-success-text: #a7dfa9;
  --relay-warning-text: #f3d78c;
  --relay-danger-text: #ffb1a7;
  --relay-radius-xs: 4px;
  --relay-radius-sm: 6px;
  --relay-radius-md: 8px;
  --relay-radius-lg: 10px;
  --relay-space-1: 4px;
  --relay-space-2: 8px;
  --relay-space-3: 12px;
  --relay-space-4: 16px;
  --relay-space-5: 20px;
  --relay-space-6: 24px;
  --relay-text-xs: 11px;
  --relay-text-sm: 12px;
  --relay-text-md: 13px;
  --relay-text-base: 14px;
  --relay-text-lg: 16px;
  --relay-text-xl: 20px;
  --relay-shadow-sm: 0 1px 2px rgb(0 0 0 / 24%);
  --relay-shadow-panel: 0 16px 48px rgb(0 0 0 / 26%);
  --relay-shadow-modal: 0 28px 90px rgb(0 0 0 / 46%);
  --relay-inset-highlight: inset 0 1px 0 rgb(255 255 255 / 5%);
  --relay-focus-ring: 0 0 0 2px var(--relay-bg), 0 0 0 4px var(--relay-ring);
  font-family: var(--relay-font-sans);
  background: var(--relay-bg);
  color: var(--relay-text);
  font-synthesis: none;
  text-rendering: optimizeLegibility;
}

* {
  box-sizing: border-box;
}

html,
body,
#root {
  width: 100%;
  height: 100%;
}

body {
  margin: 0;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  background: linear-gradient(180deg, var(--relay-chrome) 0%, var(--relay-bg) 46%);
}

button,
input,
textarea,
select {
  font: inherit;
}

button {
  min-height: 32px;
  border: 1px solid var(--relay-border);
  border-radius: var(--relay-radius-md);
  background: var(--relay-surface-2);
  color: var(--relay-text);
  padding: 0 11px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--relay-space-2);
  cursor: pointer;
  box-shadow: var(--relay-inset-highlight);
  transition:
    background-color 140ms ease,
    border-color 140ms ease,
    color 140ms ease,
    box-shadow 140ms ease,
    transform 90ms ease;
}

button:hover {
  border-color: var(--relay-border-strong);
  background: var(--relay-surface-hover);
}

button:active {
  transform: translateY(1px);
  background: var(--relay-surface-active);
  box-shadow: none;
}

button:focus-visible,
input:focus-visible,
textarea:focus-visible,
select:focus-visible {
  outline: none;
  box-shadow: var(--relay-focus-ring);
}

button:disabled {
  cursor: not-allowed;
  opacity: 0.52;
  transform: none;
}

button svg {
  flex: 0 0 auto;
  opacity: 0.86;
}

input,
textarea,
select {
  width: 100%;
  border: 1px solid var(--relay-border);
  border-radius: var(--relay-radius-md);
  background: var(--relay-input);
  color: var(--relay-text);
  padding: 8px 10px;
  outline: none;
  box-shadow: var(--relay-inset-highlight);
  transition:
    background-color 140ms ease,
    border-color 140ms ease,
    box-shadow 140ms ease;
}

input::placeholder,
textarea::placeholder {
  color: var(--relay-text-subtle);
}

input:hover,
textarea:hover,
select:hover {
  border-color: var(--relay-border-strong);
}

textarea {
  min-height: 132px;
  resize: vertical;
  line-height: 1.45;
}

select {
  color: var(--relay-text);
}

option {
  background: var(--relay-popover);
  color: var(--relay-text);
}

pre,
code {
  font-family: var(--relay-font-mono);
}

kbd {
  min-height: 18px;
  border: 1px solid rgb(255 255 255 / 22%);
  border-radius: var(--relay-radius-xs);
  background: rgb(255 255 255 / 11%);
  color: currentColor;
  padding: 1px 5px;
  font-family: var(--relay-font-mono);
  font-size: var(--relay-text-xs);
  font-weight: 650;
  line-height: 1.25;
  white-space: nowrap;
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  clip-path: inset(50%);
  white-space: nowrap;
}

::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  border: 2px solid transparent;
  border-radius: 999px;
  background: rgb(255 255 255 / 18%);
  background-clip: padding-box;
}

::-webkit-scrollbar-thumb:hover {
  background: rgb(255 255 255 / 28%);
  background-clip: padding-box;
}

.app-shell {
  display: grid;
  grid-template-columns: 272px minmax(0, 1fr);
  height: 100dvh;
  min-width: 0;
  overflow: hidden;
  background: var(--relay-chrome);
  color: var(--relay-text);
}

.sidebar {
  min-height: 0;
  border-right: 1px solid var(--relay-border);
  background: linear-gradient(180deg, color-mix(in srgb, var(--relay-sidebar) 86%, var(--relay-text)) 0%, var(--relay-sidebar) 100%);
  padding: var(--relay-space-3);
  display: flex;
  flex-direction: column;
  gap: var(--relay-space-3);
  box-shadow: var(--relay-inset-highlight);
}

.brand {

  display: flex;
  align-items: center;
  gap: 10px;
  min-width: 0;
  padding: 2px;
}

.brand-mark {
  width: 34px;
  height: 34px;
  border: 1px solid var(--relay-border-strong);
  border-radius: var(--relay-radius-md);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 8%), transparent),
    var(--relay-surface-3);
  color: var(--relay-primary-text);
  display: grid;
  place-items: center;
  font-weight: 760;
  font-size: var(--relay-text-lg);
  box-shadow: var(--relay-shadow-sm);
}

.brand h1,
.brand p,
.topbar h1,
.topbar p {
  margin: 0;
}

.brand h1 {
  font-size: var(--relay-text-lg);
  line-height: 1.1;
  letter-spacing: 0;
}

.brand p {
  margin-top: 2px;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
}

.primary-button {
  border-color: color-mix(in srgb, var(--relay-primary) 70%, transparent);
  background: var(--relay-primary);
  color: var(--relay-text-inverse);
  font-weight: 680;
  box-shadow:
    inset 0 1px 0 rgb(255 255 255 / 28%),
    0 8px 22px color-mix(in srgb, var(--relay-primary) 12%, transparent);
}

.primary-button:hover {
  border-color: var(--relay-primary-hover);
  background: var(--relay-primary-hover);
}

.primary-button:active {
  border-color: var(--relay-primary-active);
  background: var(--relay-primary-active);
}

.primary-button:disabled {
  background: var(--relay-surface-3);
  border-color: var(--relay-border);
  color: var(--relay-text-muted);
  box-shadow: none;
}

.full {
  width: 100%;
}

.sidebar-list {
  display: flex;
  flex-direction: column;
  gap: var(--relay-space-1);
  min-height: 0;
  overflow-y: auto;
  padding-right: 2px;
}

.project-group {
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.project-row-shell {
  display: grid;
  grid-template-columns: 32px minmax(0, 1fr);
  align-items: stretch;
  border: 1px solid transparent;
  border-radius: var(--relay-radius-md);
  background: transparent;
  transition:
    background-color 140ms ease,
    border-color 140ms ease,
    color 140ms ease;
}

.project-row-shell:hover {
  border-color: var(--relay-border-soft);
  background: var(--relay-surface-hover);
}

.project-row-shell.selected {
  border-color: color-mix(in srgb, var(--relay-primary) 32%, transparent);
  background: var(--relay-primary-muted);
  color: var(--relay-text);
}

.project-disclosure {
  width: 32px;
  min-height: 48px;
  border: 0;
  border-radius: var(--relay-radius-md) 0 0 var(--relay-radius-md);
  background: transparent;
  color: var(--relay-text-subtle);
  padding: 0;
  box-shadow: none;
}

.project-disclosure:hover {
  border-color: transparent;
  background: transparent;
  box-shadow: none;
}

.project-disclosure:active {
  transform: none;
}

.project-disclosure-icon {
  transition: transform 140ms ease;
}

.project-disclosure-icon.expanded {
  transform: rotate(90deg);
}

.project-row {
  width: 100%;
  min-width: 0;
  min-height: 48px;
  justify-content: space-between;
  text-align: left;
  padding: 8px 8px 8px 0;
  border: 0;
  border-radius: 0 var(--relay-radius-md) var(--relay-radius-md) 0;
  background: transparent;
  box-shadow: none;
}

.project-row:hover {
  border-color: transparent;
  background: transparent;
}

.project-row.selected {
  border-color: transparent;
  background: transparent;
  color: var(--relay-text);
}

.project-main {
  min-width: 0;
  display: grid;
  gap: 3px;
}

.project-name {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-weight: 690;
}

.project-path {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
}

.project-badges {
  color: var(--relay-warning);
  display: flex;
  align-items: center;
  gap: var(--relay-space-1);
  flex-shrink: 0;
}

.project-main .git-metadata {
  justify-self: start;
  max-width: 100%;
}

.project-swimlane-list {
  display: grid;
  gap: 2px;
  margin: 1px 0 var(--relay-space-1) 32px;
  padding-left: var(--relay-space-2);
  border-left: 1px solid var(--relay-border-soft);
}

.project-swimlane-row {
  min-height: 28px;
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  align-items: center;
  gap: var(--relay-space-2);
  border-radius: var(--relay-radius-sm);
  color: var(--relay-text-muted);
  font-size: var(--relay-text-sm);
  padding: 4px 8px;
}

.project-swimlane-name {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.project-swimlane-count {
  min-width: 24px;
  border: 1px solid var(--relay-border-soft);
  border-radius: 999px;
  background: rgb(255 255 255 / 4%);
  color: var(--relay-text);
  font-variant-numeric: tabular-nums;
  line-height: 1.35;
  padding: 1px 6px;
  text-align: center;
}

.project-swimlane-empty {
  min-height: 28px;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
  padding: 4px 8px;
}

.sidebar-actions {
  margin-top: auto;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--relay-space-2);
}

.workspace {
  min-width: 0;
  min-height: 0;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  padding: 14px 16px 12px;
  background: var(--relay-bg);
}

.topbar {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--relay-space-4);
  margin-bottom: var(--relay-space-3);
}

.topbar h1 {
  max-width: min(56vw, 720px);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-size: var(--relay-text-xl);
  line-height: 1.15;
  letter-spacing: 0;
}

.topbar p {
  max-width: min(58vw, 760px);
  margin-top: 4px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-md);
}

.project-header-meta {
  min-width: 0;
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
  margin-top: 4px;
}

.project-header-meta p {
  margin-top: 0;
}

.topbar-actions {
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-shrink: 0;
}

.search {
  width: 280px;
  min-height: 34px;
  border: 1px solid var(--relay-border);
  border-radius: var(--relay-radius-md);
  background: var(--relay-input);
  color: var(--relay-text-subtle);
  padding: 0 10px;
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  box-shadow: var(--relay-inset-highlight);
  transition:
