.priority,
.run-pill,
.labels span {
  min-height: 21px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5.5%);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
}

.git-metadata {
  min-width: 0;
  max-width: min(100%, 360px);
  min-height: 22px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5%);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
  white-space: nowrap;
}

.git-metadata svg {
  flex: 0 0 auto;
}

.git-metadata > span {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
}

.git-metadata.compact {
  max-width: 170px;
  padding-inline: 6px;
}

.git-metadata.git-loading {
  color: var(--relay-text-subtle);
}

.git-metadata.git-ready {
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.git-metadata.git-ready.dirty {
  background: var(--relay-warning-muted);
  color: var(--relay-warning-text);
}

.git-metadata.git-not_git,
.git-metadata.git-missing {
  background: color-mix(in srgb, var(--relay-surface-2) 70%, transparent);
  color: var(--relay-text-subtle);
}

.git-metadata.git-unavailable,
.git-metadata.git-error {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.priority.high,
.priority.urgent {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.priority.low {
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.run-pill.running,
.run-pill.blocked,
.run-pill.drafting {
  background: var(--relay-warning-muted);
  color: var(--relay-warning-text);
  box-shadow: inset 0 0 0 1px color-mix(in srgb, var(--relay-warning) 18%, transparent);
}

.run-pill.completed {
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.run-pill.failed,
.run-pill.cancelled {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.labels {
  margin-top: 0;
  max-height: 0;
  overflow: hidden;
  opacity: 0;
  transform: translateY(-2px);
  transition:
    max-height 180ms var(--relay-ease),
    margin-top 180ms var(--relay-ease),
    opacity 180ms var(--relay-ease),
    transform 180ms var(--relay-spring);
}

.ticket-card:hover .labels,
.ticket-card:focus-within .labels,
.ticket-card.keyboard-selected .labels {
  margin-top: 10px;
  max-height: 64px;
  opacity: 1;
  transform: translateY(0);
}

.labels .label-overflow {
  color: var(--relay-text-subtle);
}

.drag-handle {
  position: absolute;
  top: var(--relay-space-2);
  right: var(--relay-space-2);
  width: 28px;
  min-height: 28px;
  padding: 0;
  border-color: transparent;
  background: transparent;
  color: var(--relay-text-subtle);
  box-shadow: none;
  opacity: 0;
  transition:
    opacity 160ms var(--relay-ease),
    color 160ms var(--relay-ease),
    background-color 160ms var(--relay-ease),
    transform 180ms var(--relay-spring);
}

